  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using terms from the Taungoo Empire's history. Refer to the Learning Cards and Concept Breakdown for clues.",
        "codeTemplate": "The Taungoo Empire, established in the ___ century, is known for its ___ and strategic alliances.",
        "options": [
          "16th, military strength",
          "15th, economic decline",
          "17th, cultural stagnation",
          "18th, territorial loss"
        ],
        "correctAnswer": "16th, military strength",
        "explanation": "The Taungoo Empire emerged in the 16th century, renowned for its military strength and strategic alliances."
      },
      {
        "instruction": "Use the information from the Visualizing the Taungoo Empire Walkthrough to fill in the blanks.",
        "codeTemplate": "The geographic scope of the Taungoo Empire included much of present-day ___, showcasing its influence over ___ Asia.",
        "options": [
          "Thailand, Southeast",
          "Myanmar, Southeast",
          "Vietnam, East",
          "Laos, South"
        ],
        "correctAnswer": "Myanmar, Southeast",
        "explanation": "The Taungoo Empire's territory spanned much of present-day Myanmar, influencing Southeast Asia."
      }
    ]
  }
}
